/**
 * Valida se una stringa fornita è un indirizzo email valido.
 * 
 * Nota: Questa implementazione utilizza una regex robusta per la maggior parte dei casi comuni,
 * ma non è garantita a coprire ogni singola eccezione definita dallo standard RFC 5322,
 * poiché questo è notoriamente complesso. Il miglioramento principale riguarda la gestione dei TLD.
 * 
 * @param email L'indirizzo email da validare.
 * @returns True se l'email è valida, false altrimenti.
 */
const validateEmail = (email: string): boolean => {
  if (!email) {
    return false;
  }

  // Regex migliorata: 
  // 1. Local part: [a-zA-Z0-9._%+-]+ (Permette caratteri comuni)
  // 2. Domain name: (?:[a-zA-Z0-9-]+\.)+ (Permette segmenti con caratteri alfanumerici e trattini, seguiti da un punto)
  // 3. TLD: [a-zA-Z0-9]{2,} (CORRETTO: Include cifre per TLD moderni come .info, .museum, ecc.)
  // 
  // Questa regex è un buon compromesso tra accuratezza e complessità.
  const emailRegex = new RegExp(
    /^(([^<>()[\\]\\.,;:\s@"]+(\.[^<>()[\\]\\.,;:\s@"]+)*)|(\[[^\]]+\]))@(([a-zA-Z0-9-]+\.)+[a-zA-Z0-9]{2,})$/
  );

  return emailRegex.test(email);
};

// Esempi di utilizzo:
// console.log(`test@example.com: ${validateEmail('test@example.com')}`); // true
// console.log(`user.name+tag@sub.domain.co1: ${validateEmail('user.name+tag@sub.domain.co1')}`); // true (Test TLD con cifre)
// console.log(`invalid-email: ${validateEmail('invalid-email')}`); // false
// console.log(`@missinglocal.com: ${validateEmail('@missinglocal.com')}`); // false
// console.log(`local@.com: ${validateEmail('local@.com')}`); // false

export { validateEmail };
